-// Standard GELU activation (exact, using erf)
-// GELU(x) = x * 0.5 * (1 + erf(x / sqrt(2)))
-fn gelu(x: f32) f32 {
-    const sqrt2_inv: f32 = 0.7071067811865476; // 1 / sqrt(2)
-    return x * 0.5 * (1.0 + erf(x * sqrt2_inv));
-}
