-// Softmax over last dimension
-fn softmax(data: []f32, seq_len: usize) void {
-    for (0..seq_len) |i| {
-        const row = data[i * seq_len .. (i + 1) * seq_len];
-
-        // Find max for numerical stability
-        var max_val: f32 = row[0];
-        for (row[1..]) |v| {
-            if (v > max_val) max_val = v;
-        }
-
-        // Exp and sum
-        var sum: f32 = 0;
-        for (row) |*v| {
-            v.* = @exp(v.* - max_val);
-            sum += v.*;
-        }
-
-        // Normalize
-        for (row) |*v| {
-            v.* /= sum;
-        }
-    }
-}
